var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>ARC-CS1 도시관리국 행정 2부 비서관의 프라이빗 메일입니다.</color>`,JPN:`<color=#ffd34c>ARC-CS1都市管理局行政2部の秘書官からプライベートメールです。</color>`,ENG:`<color=#ffd34c>A private mail arrived from ARC-CS1 City Managements' 2nd Division Secretary.</color>`,TWN:`<color=#ffd34c>來自ARC-CS1城市管理局行政2部秘書長的機密郵件。</color>`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_CUTSCEN_BEEP`},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`이번 의뢰를 성공적으로 완수해 주셔서 감사드립니다.`,JPN:`依頼を見事完遂していただき、ありがとうございます。`,ENG:`Thank you for completing our request successfully.`,TWN:`感謝你完成了這次的委託。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`건설 중이던 시설물은 조만간 기동에 들어갈 예정입니다.`,JPN:`建設中だった施設は、近々稼働する予定です。`,ENG:`All of the facilities that were under construction will be active soon.`,TWN:`建設中的設施預計最近幾天進入啟動階段。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`추후 의뢰 수요가 발생할 시 적극 추천드리도록 하겠습니다.`,JPN:`今後、依頼が発生した場合は積極的に推薦させていただきます。`,ENG:`I will make positive recommendations about your company if another commission is required.`,TWN:`之後如果再有委託需求，我們會積極地推薦你。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`요구에 정확히 부응해 주신 부분에 대하여 다시 한 번 감사 인사 드립니다.`,JPN:`今回は依頼に応じていただき、誠にありがとうございました。`,ENG:`Thank you again for satisfying our demands.`,TWN:`再次感謝你回應了我們的請求。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};